CREATE TABLE IF NOT EXISTS ai_company_simulation_runs (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), workspace_id UUID NOT NULL REFERENCES workspaces(id) ON DELETE CASCADE, run_payload JSONB NOT NULL DEFAULT '{}'::jsonb, simulation_only BOOLEAN NOT NULL DEFAULT TRUE, no_autonomous_execution BOOLEAN NOT NULL DEFAULT TRUE, no_customer_contact BOOLEAN NOT NULL DEFAULT TRUE, no_pricing_changes BOOLEAN NOT NULL DEFAULT TRUE, requires_human_review BOOLEAN NOT NULL DEFAULT TRUE, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
CREATE TABLE IF NOT EXISTS ai_company_simulation_scenarios (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), workspace_id UUID NOT NULL REFERENCES workspaces(id) ON DELETE CASCADE, run_id UUID NOT NULL REFERENCES ai_company_simulation_runs(id) ON DELETE CASCADE, scenario_type TEXT NOT NULL, scenario_payload JSONB NOT NULL DEFAULT '{}'::jsonb, simulation_only BOOLEAN NOT NULL DEFAULT TRUE, no_autonomous_execution BOOLEAN NOT NULL DEFAULT TRUE, no_customer_contact BOOLEAN NOT NULL DEFAULT TRUE, no_pricing_changes BOOLEAN NOT NULL DEFAULT TRUE, requires_human_review BOOLEAN NOT NULL DEFAULT TRUE, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
CREATE TABLE IF NOT EXISTS ai_company_simulation_results (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), workspace_id UUID NOT NULL REFERENCES workspaces(id) ON DELETE CASCADE, run_id UUID NOT NULL REFERENCES ai_company_simulation_runs(id) ON DELETE CASCADE, result_payload JSONB NOT NULL DEFAULT '{}'::jsonb, simulation_only BOOLEAN NOT NULL DEFAULT TRUE, no_autonomous_execution BOOLEAN NOT NULL DEFAULT TRUE, no_customer_contact BOOLEAN NOT NULL DEFAULT TRUE, no_pricing_changes BOOLEAN NOT NULL DEFAULT TRUE, requires_human_review BOOLEAN NOT NULL DEFAULT TRUE, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
CREATE TABLE IF NOT EXISTS ai_company_simulation_risks (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), workspace_id UUID NOT NULL REFERENCES workspaces(id) ON DELETE CASCADE, run_id UUID NOT NULL REFERENCES ai_company_simulation_runs(id) ON DELETE CASCADE, risk_type TEXT NOT NULL, severity TEXT NOT NULL, risk_payload JSONB NOT NULL DEFAULT '{}'::jsonb, simulation_only BOOLEAN NOT NULL DEFAULT TRUE, no_autonomous_execution BOOLEAN NOT NULL DEFAULT TRUE, no_customer_contact BOOLEAN NOT NULL DEFAULT TRUE, no_pricing_changes BOOLEAN NOT NULL DEFAULT TRUE, requires_human_review BOOLEAN NOT NULL DEFAULT TRUE, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
CREATE TABLE IF NOT EXISTS ai_company_simulation_memory (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), workspace_id UUID NOT NULL REFERENCES workspaces(id) ON DELETE CASCADE, memory_key TEXT NOT NULL, memory_value JSONB NOT NULL DEFAULT '{}'::jsonb, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
